@section('script')
    <script type="text/javascript">
        let currentReportId = null;
        let reportModal = null;

        document.addEventListener('DOMContentLoaded', function() {
            reportModal = new bootstrap.Modal(document.getElementById('reportModal'), {
                backdrop: 'static',
                keyboard: false
            });
            fetchReports();

            // Handle form submission
            document.getElementById('formReport').addEventListener('submit', function(event) {
                event.preventDefault();
                saveFormData();
            });

            // Reset form when modal is hidden
            document.getElementById('reportModal').addEventListener('hidden.bs.modal', function() {
                resetForm();
                // Remove any lingering backdrop
                const backdrop = document.querySelector('.modal-backdrop');
                if (backdrop) {
                    backdrop.remove();
                }
                // Ensure body classes are removed
                document.body.classList.remove('modal-open');
                document.body.style.overflow = '';
                document.body.style.paddingRight = '';
            });

            // Cleanup on modal show
            document.getElementById('reportModal').addEventListener('show.bs.modal', function() {
                // Remove any previous backdrop
                const backdrops = document.querySelectorAll('.modal-backdrop');
                backdrops.forEach(backdrop => backdrop.remove());
            });
        });

        function fetchReports() {
            fetch('/user/get-device-report')
                .then(response => {
                    if (!response.ok) {
                        throw new Error('Network response was not ok');
                    }
                    return response.json();
                })
                .then(data => {
                    if (!data.success) {
                        Swal.fire({
                            icon: 'error',
                            title: 'Error',
                            text: data.message || 'Failed to load reports'
                        });
                        return;
                    }

                    // Populate device select options
                    const deviceIdSelect = document.getElementById('deviceId');
                    deviceIdSelect.innerHTML = '<option value="" disabled selected>Select Device ID</option>';

                    if (data.available_devices && data.available_devices.length > 0) {
                        data.available_devices.forEach(device => {
                            const option = document.createElement('option');
                            option.value = device.device_id;
                            option.textContent = `${device.device_id} (${device.device_category})`;
                            deviceIdSelect.appendChild(option);
                        });
                    }

                    // Populate the report table
                    const reportTableBody = document.getElementById('reportTableBody');
                    reportTableBody.innerHTML = ''; // Clear existing rows

                    if (data.report && data.report.length > 0) {
                        data.report.forEach(report => {
                            const row = document.createElement('tr');
                            row.innerHTML = `
                            <td>${report.device_category || 'N/A'}</td>
                            <td>${report.device_id || 'N/A'}</td>
                            <td><span class="badge bg-info">${report.schedule || 'N/A'}</span></td>
                            <td>${report.email || 'N/A'}</td>
                            <td><span class="badge ${report.status === 'Active' ? 'bg-success' : 'bg-secondary'}">${report.status || 'Inactive'}</span></td>
                            @if($accessCrud)
                            <td>
                                <button class="btn btn-sm btn-primary me-2" onclick="editReport(${report.id})">
                                    <i class="bi bi-pencil"></i> Edit
                                </button>
                                <button class="btn btn-sm btn-danger" onclick="deleteReport(${report.id})">
                                    <i class="bi bi-trash"></i> Delete
                                </button>
                            </td>
                            @endif
                        `;
                            reportTableBody.appendChild(row);
                        });
                    } else {
                        const row = document.createElement('tr');
                        row.innerHTML = `
                        <td colspan="6" class="text-center text-muted">
                            <i class="bi bi-inbox"></i> No reports found. Click "Add New Report" to create one.
                        </td>
                    `;
                        reportTableBody.appendChild(row);
                    }
                })
                .catch(error => {
                    console.error('Error fetching reports:', error);
                    Swal.fire({
                        icon: 'error',
                        title: 'Error',
                        text: 'Failed to load reports. Please refresh the page.'
                    });
                });
        }

        function saveFormData() {
            const deviceId = document.getElementById('deviceId').value;
            const schedule = document.getElementById('schedule').value;
            const email = document.getElementById('email').value;
            const status = document.getElementById('status').value;

            // Validate form fields
            if (!deviceId || !schedule || !email || !status) {
                Swal.fire({
                    icon: 'warning',
                    title: 'Validation Error',
                    text: 'Please fill in all required fields.'
                });
                return;
            }

            // Validate email format
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(email)) {
                Swal.fire({
                    icon: 'warning',
                    title: 'Invalid Email',
                    text: 'Please enter a valid email address.'
                });
                return;
            }

            const formData = {
                device_id: deviceId,
                schedule: schedule,
                email: email,
                status: status
            };

            // Determine if this is an update or create
            const isUpdate = currentReportId !== null;
            const url = isUpdate ? '/user/update-device-report' : '/user/save-device-report';

            if (isUpdate) {
                formData.id = currentReportId;
            }

            // Disable submit button
            const submitBtn = document.querySelector('#formReport button[type="submit"]');
            const originalText = submitBtn.innerHTML;
            submitBtn.disabled = true;
            submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-1"></span> Saving...';

            fetch(url, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'X-CSRF-TOKEN': '{{ csrf_token() }}'
                    },
                    body: JSON.stringify(formData)
                })
                .then(response => {
                    if (!response.ok) {
                        return response.json().then(err => Promise.reject(err));
                    }
                    return response.json();
                })
                .then(data => {
                    if (data.success) {
                        Swal.fire({
                            icon: 'success',
                            title: 'Success',
                            text: data.message || 'Report saved successfully!',
                            timer: 2000,
                            showConfirmButton: false
                        });
                        reportModal.hide();
                        fetchReports();
                    } else {
                        Swal.fire({
                            icon: 'error',
                            title: 'Error',
                            text: data.message || 'Failed to save report.'
                        });
                    }
                })
                .catch(error => {
                    console.error('Error saving report:', error);
                    let errorMessage = 'An error occurred while saving the report.';

                    if (error.errors) {
                        // Laravel validation errors
                        errorMessage = Object.values(error.errors).flat().join(', ');
                    } else if (error.message) {
                        errorMessage = error.message;
                    }

                    Swal.fire({
                        icon: 'error',
                        title: 'Error',
                        text: errorMessage
                    });
                })
                .finally(() => {
                    submitBtn.disabled = false;
                    submitBtn.innerHTML = originalText;
                });
        }

        function editReport(reportId) {
            // Show loading
            Swal.fire({
                title: 'Loading...',
                text: 'Fetching report data',
                allowOutsideClick: false,
                didOpen: () => {
                    Swal.showLoading();
                }
            });

            fetch(`/user/get-device-report/${reportId}`)
                .then(response => {
                    if (!response.ok) {
                        throw new Error('Failed to fetch report');
                    }
                    return response.json();
                })
                .then(data => {
                    Swal.close();

                    if (data.success && data.report) {
                        const report = data.report;

                        // Set device ID as locked (disabled and display only)
                        const deviceIdSelect = document.getElementById('deviceId');
                        deviceIdSelect.innerHTML = '';

                        // Add single option with current device (locked)
                        const currentOption = document.createElement('option');
                        currentOption.value = report.device_id;
                        currentOption.textContent = report.device_id;
                        currentOption.selected = true;
                        deviceIdSelect.appendChild(currentOption);

                        // Disable the select to lock it
                        deviceIdSelect.disabled = true;

                        // Set form values
                        currentReportId = report.id;
                        document.getElementById('schedule').value = report.schedule;
                        document.getElementById('email').value = report.email;
                        document.getElementById('status').value = report.status;

                        // Update modal title
                        document.getElementById('reportModalLabel').textContent = 'Edit Report';

                        // Show modal
                        reportModal.show();
                    } else {
                        Swal.fire({
                            icon: 'error',
                            title: 'Error',
                            text: data.message || 'Failed to load report data.'
                        });
                    }
                })
                .catch(error => {
                    console.error('Error fetching report:', error);
                    Swal.close();
                    Swal.fire({
                        icon: 'error',
                        title: 'Error',
                        text: 'Failed to load report data. Please try again.'
                    });
                });
        }

        function deleteReport(reportId) {
            Swal.fire({
                title: 'Are you sure?',
                text: "You won't be able to revert this!",
                icon: 'warning',
                showCancelButton: true,
                confirmButtonColor: '#d33',
                cancelButtonColor: '#3085d6',
                confirmButtonText: 'Yes, delete it!',
                cancelButtonText: 'Cancel'
            }).then((result) => {
                if (result.isConfirmed) {
                    // Show loading
                    Swal.fire({
                        title: 'Deleting...',
                        text: 'Please wait',
                        allowOutsideClick: false,
                        didOpen: () => {
                            Swal.showLoading();
                        }
                    });

                    fetch(`/user/delete-device-report/${reportId}`, {
                            method: 'DELETE',
                            headers: {
                                'Content-Type': 'application/json',
                                'X-CSRF-TOKEN': '{{ csrf_token() }}'
                            }
                        })
                        .then(response => {
                            if (!response.ok) {
                                return response.json().then(err => Promise.reject(err));
                            }
                            return response.json();
                        })
                        .then(data => {
                            if (data.success) {
                                Swal.fire({
                                    icon: 'success',
                                    title: 'Deleted!',
                                    text: data.message || 'Report has been deleted.',
                                    timer: 2000,
                                    showConfirmButton: false
                                });
                                fetchReports();
                            } else {
                                Swal.fire({
                                    icon: 'error',
                                    title: 'Error',
                                    text: data.message || 'Failed to delete report.'
                                });
                            }
                        })
                        .catch(error => {
                            console.error('Error deleting report:', error);
                            const errorMessage = error.message || 'Failed to delete report. Please try again.';
                            Swal.fire({
                                icon: 'error',
                                title: 'Error',
                                text: errorMessage
                            });
                        });
                }
            });
        }

        function resetForm() {
            currentReportId = null;
            document.getElementById('formReport').reset();
            document.getElementById('reportModalLabel').textContent = 'Add Report';

            // Re-enable device select for new report
            const deviceIdSelect = document.getElementById('deviceId');
            deviceIdSelect.disabled = false;

            // Reload available devices
            fetch('/user/get-device-report')
                .then(response => response.json())
                .then(data => {
                    if (data.success && data.available_devices) {
                        deviceIdSelect.innerHTML = '<option value="" disabled selected>Select Device ID</option>';
                        data.available_devices.forEach(device => {
                            const option = document.createElement('option');
                            option.value = device.device_id;
                            option.textContent = `${device.device_id} (${device.device_category})`;
                            deviceIdSelect.appendChild(option);
                        });
                    }
                })
                .catch(error => {
                    console.error('Error fetching devices:', error);
                });
        }
    </script>

    <script type="text/javascript">

        // script for form quick report
        let quickReportForm = @json($deviceCategories);
        let currentReportData = null; // Store current report data for export
        let firstDeviceId = @json($firstDeviceId ?? null);

        // Set default date range (1 day)
        const today = new Date();
        const yesterday = new Date(today);
        yesterday.setDate(yesterday.getDate() - 1);

        const formatDate = (date) => {
            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        };

        document.getElementById('quickStartDate').value = formatDate(yesterday);
        document.getElementById('quickEndDate').value = formatDate(today);

        // Isikan select device category
        let deviceCategorySelect = document.getElementById('deviceCategory');

        // Tambahkan opsi default
        let defaultCategoryOption = document.createElement('option');
        defaultCategoryOption.value = "";
        defaultCategoryOption.textContent = "Select Device Category";
        defaultCategoryOption.disabled = true;
        defaultCategoryOption.selected = true;
        deviceCategorySelect.appendChild(defaultCategoryOption);

        // Isi dengan kategori dari data
        let firstCategory = null;
        quickReportForm.forEach((category, index) => {
            let option = document.createElement('option');
            option.value = category.device_category;
            option.textContent = category.device_category;
            deviceCategorySelect.appendChild(option);

            // Store first category for auto-selection
            if (index === 0) {
                firstCategory = category.device_category;
            }
        });

        // Auto-select first category and device if available
        if (firstCategory && firstDeviceId) {
            deviceCategorySelect.value = firstCategory;

            // Populate device dropdown
            let deviceIdSelect = document.getElementById('quickDeviceId');
            deviceIdSelect.innerHTML = '<option value="" disabled>Select Device ID</option>';

            let selectedCategoryObj = quickReportForm.find(cat => cat.device_category === firstCategory);
            if (selectedCategoryObj) {
                selectedCategoryObj.devices.forEach(device => {
                    let option = document.createElement('option');
                    option.value = device.device_id;
                    option.textContent = device.device_id;
                    if (device.device_id === firstDeviceId) {
                        option.selected = true;
                    }
                    deviceIdSelect.appendChild(option);
                });
            }

            // Auto-load data after a short delay to ensure DOM is ready
            setTimeout(() => {
                loadQuickReportData();
            }, 500);
        }

        // Event onchange select device category
        deviceCategorySelect.addEventListener('change', function() {
            let selectedCategory = this.value;
            let deviceIdSelect = document.getElementById('quickDeviceId');

            // Clear previous options and add default option
            deviceIdSelect.innerHTML = '<option value="" disabled selected>Select Device ID</option>';

            // Find the selected category object
            let selectedCategoryObj = quickReportForm.find(cat => cat.device_category === selectedCategory);

            if (selectedCategoryObj) {
                selectedCategoryObj.devices.forEach(device => {
                    let option = document.createElement('option');
                    option.value = device.device_id;
                    option.textContent = device.device_id;
                    deviceIdSelect.appendChild(option);
                });
            }
        });

        // Handle submit form quick report
        document.getElementById('quickReportForm').addEventListener('submit', function(e) {
            e.preventDefault();
            loadQuickReportData();
        });

        function loadQuickReportData() {
            const deviceId = document.getElementById('quickDeviceId').value;
            const startDate = document.getElementById('quickStartDate').value;
            const endDate = document.getElementById('quickEndDate').value;

            // Validate form
            if (!deviceId || !startDate || !endDate) {
                Swal.fire({
                    icon: 'warning',
                    title: 'Validation Error',
                    text: 'Please fill in all required fields.'
                });
                return;
            }

            // Show loading
            Swal.fire({
                title: 'Loading...',
                text: 'Retrieving report data',
                allowOutsideClick: false,
                didOpen: () => {
                    Swal.showLoading();
                }
            });

            // Fetch data from API
            fetch(`/user/report-table-data?device_id=${encodeURIComponent(deviceId)}&start_date=${encodeURIComponent(startDate)}&end_date=${encodeURIComponent(endDate)}`)
                .then(response => {
                    if (!response.ok) {
                        return response.json().then(err => Promise.reject(err));
                    }
                    return response.json();
                })
                .then(data => {
                    Swal.close();

                    if (data.success) {
                        if (data.data && data.data.length > 0) {
                            currentReportData = data; // Store for export
                            displayQuickReportTable(data);
                            Swal.fire({
                                icon: 'success',
                                title: 'Success',
                                text: `Loaded ${data.total_records} records`,
                                timer: 2000,
                                showConfirmButton: false
                            });
                        } else {
                            // Clear table and stored data
                            currentReportData = null;
                            document.getElementById('quickReportTable').innerHTML = '';
                            Swal.fire({
                                icon: 'info',
                                title: 'No Data',
                                text: data.message || 'No data found for the selected date range.'
                            });
                        }
                    } else {
                        Swal.fire({
                            icon: 'error',
                            title: 'Error',
                            text: data.message || 'Failed to load report data.'
                        });
                    }
                })
                .catch(error => {
                    console.error('Error loading quick report:', error);
                    Swal.close();

                    let errorMessage = 'Failed to load report data. Please try again.';
                    if (error.errors) {
                        errorMessage = Object.values(error.errors).flat().join(', ');
                    } else if (error.message) {
                        errorMessage = error.message;
                    }

                    Swal.fire({
                        icon: 'error',
                        title: 'Error',
                        text: errorMessage
                    });
                });
        }

        function displayQuickReportTable(reportData) {
            const table = document.getElementById('quickReportTable');
            table.innerHTML = ''; // Clear existing content

            if (!reportData.data || reportData.data.length === 0) {
                table.innerHTML = '<tr><td colspan="100%" class="text-center text-muted">No data available</td></tr>';
                return;
            }

            // Create table header
            const thead = document.createElement('thead');
            thead.className = 'table-dark';
            thead.style.position = 'sticky';
            thead.style.top = '0';
            thead.style.zIndex = '10';
            const headerRow = document.createElement('tr');

            // Static columns
            headerRow.innerHTML = `
                <th scope="col" class="text-center">No</th>
                <th scope="col" class="text-center">Date</th>
                <th scope="col" class="text-center">Time</th>
            `;

            // Dynamic parameter columns
            reportData.parameters.forEach(param => {
                const th = document.createElement('th');
                th.scope = 'col';
                th.className = 'text-center';
                th.innerHTML = `${param.parameter_label || param.parameter_name}<br><small>(${param.parameter_unit || '-'})</small>`;
                headerRow.appendChild(th);
            });

            thead.appendChild(headerRow);
            table.appendChild(thead);

            // Create table body
            const tbody = document.createElement('tbody');

            reportData.data.forEach(row => {
                const tr = document.createElement('tr');

                // Static columns
                tr.innerHTML = `
                    <td class="text-center">${row.no}</td>
                    <td class="text-center">${row.date}</td>
                    <td class="text-center">${row.time}</td>
                `;

                // Dynamic parameter columns
                reportData.parameters.forEach(param => {
                    const td = document.createElement('td');
                    td.className = 'text-center';
                    const value = row[param.parameter_name];
                    td.textContent = value !== null && value !== undefined ? value : '-';
                    tr.appendChild(td);
                });

                tbody.appendChild(tr);
            });

            table.appendChild(tbody);

            // Show report info
            console.log(`Quick Report: ${reportData.device_id} | ${reportData.total_records} records | ${reportData.date_range.start} to ${reportData.date_range.end}`);
        }

        // Export PDF button handler
        document.getElementById('exportPdfBtn').addEventListener('click', function() {
            const deviceId = document.getElementById('quickDeviceId').value;
            const startDate = document.getElementById('quickStartDate').value;
            const endDate = document.getElementById('quickEndDate').value;

            if (!deviceId || !startDate || !endDate || !currentReportData) {
                Swal.fire({
                    icon: 'warning',
                    title: 'Warning',
                    text: 'Please load the report data first by clicking Show button.'
                });
                return;
            }

            exportToPDF();
        });

        function exportToPDF() {
            const deviceId = document.getElementById('quickDeviceId').value;
            const startDate = document.getElementById('quickStartDate').value;
            const endDate = document.getElementById('quickEndDate').value;

            // Show loading
            Swal.fire({
                title: 'Generating PDF...',
                text: 'Please wait',
                allowOutsideClick: false,
                didOpen: () => {
                    Swal.showLoading();
                }
            });

            // Load jsPDF and autoTable from CDN if not already loaded
            if (typeof jspdf === 'undefined') {
                const script1 = document.createElement('script');
                script1.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
                script1.onload = function() {
                    const script2 = document.createElement('script');
                    script2.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.5.31/jspdf.plugin.autotable.min.js';
                    script2.onload = function() {
                        generatePDF();
                    };
                    document.head.appendChild(script2);
                };
                document.head.appendChild(script1);
            } else {
                generatePDF();
            }

            function generatePDF() {
                try {
                    const { jsPDF } = window.jspdf;
                    const doc = new jsPDF('l', 'mm', 'a4'); // Landscape orientation
                    const pageWidth = doc.internal.pageSize.getWidth();
                    const pageHeight = doc.internal.pageSize.getHeight();

                    // Example logo base64 (Simple blue/gray icon - Replace with your actual logo)
                    const logoBase64 = `data:image/png;base64,`;
                    // Powered by icon base64 (Small gear/settings icon)
                    const poweredByIcon = `data:image/jpeg;base64,`;
                    // Header function
                    const addHeader = (doc) => {
                        // Add logo/image
                        try {
                            doc.addImage(logoBase64, 'PNG', 14, 1, 30, 24);
                        } catch (e) {
                            // Fallback to rectangle if image fails
                            doc.setDrawColor(52, 58, 64);
                            doc.setLineWidth(0.5);
                            doc.rect(14, 8, 15, 12);
                            doc.setFontSize(8);
                            doc.text('LOGO', 18, 15);
                        }
                        
                        let yPos = 10;
                        
                        // Title: DATA REPORT
                        doc.setFontSize(16);
                        doc.setFont(undefined, 'bold');
                        doc.setTextColor(33, 37, 41);
                        doc.text('DATA REPORT', 48, yPos);
                        yPos += 5;
                        
                        // Device and Category
                        doc.setFontSize(9);
                        doc.setFont(undefined, 'normal');
                        doc.setTextColor(73, 80, 87);
                        doc.text(`Device: ${currentReportData.device_id} | Category: ${currentReportData.device_category}`, 48, yPos);
                        yPos += 4;
                        
                        // Parameters - auto split if too long
                        const paramLabels = currentReportData.parameters.map(p => p.parameter_label).join(', ');
                        const maxWidth = pageWidth - 48 - 14; // Available width from text start to right margin
                        doc.setFontSize(9);
                        doc.setFont(undefined, 'normal');
                        
                        // Check if parameters fit in one line
                        const paramText = `Parameters: ${paramLabels}`;
                        const paramTextWidth = doc.getTextWidth(paramText);
                        
                        if (paramTextWidth <= maxWidth) {
                            // Fits in one line
                            doc.text(paramText, 48, yPos);
                            yPos += 4;
                        } else {
                            // Split into multiple lines
                            doc.text('Parameters:', 48, yPos);
                            yPos += 4;
                            
                            const splitParams = doc.splitTextToSize(paramLabels, maxWidth);
                            splitParams.forEach(line => {
                                doc.text(line, 48, yPos);
                                yPos += 3.5;
                            });
                            yPos += 0.5;
                        }
                        
                        // Period, Records, and Generated - distributed layout (left, center, right)
                        const periodText = `Period: ${currentReportData.date_range.start} to ${currentReportData.date_range.end}`;
                        const recordsText = `Records: ${currentReportData.total_records}`;
                        const generatedText = `Generated: ${new Date().toLocaleString()}`;
                        
                        // Left - Period
                        doc.text(periodText, 48, yPos);
                        
                        // Center - Records
                        const centerX = pageWidth / 2;
                        const recordsWidth = doc.getTextWidth(recordsText);
                        doc.text(recordsText, centerX - (recordsWidth / 2), yPos);
                        
                        // Right - Generated
                        const generatedWidth = doc.getTextWidth(generatedText);
                        doc.text(generatedText, pageWidth - 14 - generatedWidth, yPos);
                        
                        yPos += 2;

                        // Add line separator
                        doc.setDrawColor(52, 58, 64);
                        doc.setLineWidth(0.8);
                        doc.line(14, yPos, pageWidth - 14, yPos);
                    };

                    // Footer function
                    const addFooter = (doc, pageNum, totalPages) => {
                        const footerY = pageHeight - 10;
                        
                        // Footer separator line
                        doc.setDrawColor(200, 200, 200);
                        doc.setLineWidth(0.3);
                        doc.line(14, pageHeight - 17, pageWidth - 14, pageHeight - 17);
                        
                        // Left side - Page numbers
                        doc.setFontSize(9);
                        doc.setFont(undefined, 'normal');
                        doc.setTextColor(108, 117, 125);
                        doc.text(`Page ${pageNum} of ${totalPages}`, 14, footerY);
                        
                        // Right side - Powered by text with icon
                        doc.setFontSize(9);
                        doc.setTextColor(52, 58, 64);
                        const poweredText = 'Powered by';
                        const textWidth = doc.getTextWidth(poweredText);
                        const iconSize = 10;
                        const totalWidth = textWidth + iconSize + 4;
                        const startX = pageWidth - 14 - totalWidth;
                        
                        // Draw "Powered by" text
                        doc.text(poweredText, startX, footerY+3);
                        
                        // Add icon after "Powered by"
                        try {
                            doc.addImage(poweredByIcon, 'PNG', startX + textWidth + 4, footerY - 3, 12, 10);
                        } catch (e) {
                            // Fallback to lightning symbol
                            doc.setFontSize(8);
                            doc.text('\u26a1', startX + textWidth + 2, footerY);
                        }
                    };

                    // Add initial header
                    addHeader(doc);

                    // Prepare table headers
                    const headers = [['No', 'Date', 'Time']];
                    currentReportData.parameters.forEach(param => {
                        headers[0].push(`${param.parameter_label}\n(${param.parameter_unit})`);
                    });

                    // Prepare table body
                    const body = currentReportData.data.map(row => {
                        const rowData = [row.no, row.date, row.time];
                        currentReportData.parameters.forEach(param => {
                            const value = row[param.parameter_name];
                            rowData.push(value !== null && value !== undefined ? value.toString() : '-');
                        });
                        return rowData;
                    });

                    // Generate table with headers and footers
                    doc.autoTable({
                        head: headers,
                        body: body,
                        startY: 27,
                        margin: { top: 27, bottom: 15, left: 14, right: 14 },
                        theme: 'striped',
                        styles: {
                            fontSize: 8,
                            cellPadding: 3,
                            lineColor: [220, 220, 220],
                            lineWidth: 0.1
                        },
                        headStyles: {
                            fillColor: [52, 58, 64],
                            textColor: [255, 255, 255],
                            fontStyle: 'bold',
                            fontSize: 9,
                            halign: 'center',
                            valign: 'middle',
                            cellPadding: 4
                        },
                        columnStyles: {
                            0: { cellWidth: 12, halign: 'center' },
                            1: { cellWidth: 25, halign: 'center' },
                            2: { cellWidth: 20, halign: 'center' }
                        },
                        alternateRowStyles: {
                            fillColor: [248, 249, 250]
                        },
                        didDrawPage: function(data) {
                            // Add header on each page
                            addHeader(doc);
                            
                            // Add footer on each page
                            addFooter(doc, data.pageNumber, doc.internal.getNumberOfPages());
                        }
                    });
                    
                    // Update page numbers after table is complete (for accurate total pages)
                    const totalPages = doc.internal.getNumberOfPages();
                    for (let i = 1; i <= totalPages; i++) {
                        doc.setPage(i);
                        const footerY = pageHeight - 10;
                        
                        // Clear previous footer area
                        doc.setFillColor(255, 255, 255);
                        doc.rect(0, footerY - 5, pageWidth, 10, 'F');
                        
                        // Redraw footer with correct page numbers
                        addFooter(doc, i, totalPages);
                    }

                    // Save PDF
                    const filename = `Report_${currentReportData.device_id}_${startDate}_to_${endDate}.pdf`;
                    doc.save(filename);

                    Swal.close();
                    Swal.fire({
                        icon: 'success',
                        title: 'Success',
                        text: 'PDF exported successfully!',
                        timer: 2000,
                        showConfirmButton: false
                    });
                } catch (error) {
                    console.error('Error generating PDF:', error);
                    Swal.close();
                    Swal.fire({
                        icon: 'error',
                        title: 'Export Failed',
                        text: 'Failed to export PDF. Please try again.'
                    });
                }
            }
        }

        // Export Excel button handler
        document.getElementById('exportExcelBtn').addEventListener('click', function() {
            const deviceId = document.getElementById('quickDeviceId').value;
            const startDate = document.getElementById('quickStartDate').value;
            const endDate = document.getElementById('quickEndDate').value;

            if (!deviceId || !startDate || !endDate || !currentReportData) {
                Swal.fire({
                    icon: 'warning',
                    title: 'Warning',
                    text: 'Please load the report data first by clicking Show button.'
                });
                return;
            }

            exportToExcel();
        });

        function exportToExcel() {
            const deviceId = document.getElementById('quickDeviceId').value;
            const startDate = document.getElementById('quickStartDate').value;
            const endDate = document.getElementById('quickEndDate').value;

            // Show loading
            Swal.fire({
                title: 'Generating Excel...',
                text: 'Please wait',
                allowOutsideClick: false,
                didOpen: () => {
                    Swal.showLoading();
                }
            });

            // Create form data to send to server
            const params = new URLSearchParams({
                device_id: deviceId,
                start_date: startDate,
                end_date: endDate
            });

            // Send request to server
            window.location.href = `/user/export-report-excel?${params.toString()}`;

            // Close loading after a short delay
            setTimeout(() => {
                Swal.close();
                Swal.fire({
                    icon: 'success',
                    title: 'Success',
                    text: 'Excel export started!',
                    timer: 2000,
                    showConfirmButton: false
                });
            }, 1000);
        }

        
    </script>
@endsection
